void solve(vector<int>& nums) {
   for (int i = 0; i < nums.size(); i++) {
      int min_idx = i;
      for (int j = i + 1; j < nums.size(); j++) {
         if (nums[j] < nums[min_idx]) {
            min_idx = j;
         }
      }
      swap(nums[i], nums[min_idx]);
   }
}

